#include <iostream>
using namespace std;

int main() {
    int choice, num;
    cout << "1. Even/Odd\n2. Positive/Negative\n3. Exit\n";
    cout << "Enter choice: ";
    cin >> choice;

    switch(choice) {
        case 1:
            cout << "Enter number: ";
            cin >> num;
            if(num % 2 == 0)
                cout << "Even";
            else
                cout << "Odd";
            break;
        case 2:
            cout << "Enter number: ";
            cin >> num;
            if(num > 0)
                cout << "Positive";
            else if(num < 0)
                cout << "Negative";
            else
                cout << "Zero";
            break;
        case 3:
            cout << "Exiting...";
            break;
        default:
            cout << "Invalid choice";
    }
    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int A[3][3], B[3][3], C[3][3];

    // Input matrix A
    cout << "Enter 9 elements for matrix A:\n";
    for(int i = 0; i < 3; i++)
        for(int j = 0; j < 3; j++)
            cin >> A[i][j];

    // Input matrix B
    cout << "Enter 9 elements for matrix B:\n";
    for(int i = 0; i < 3; i++)
        for(int j = 0; j < 3; j++)
            cin >> B[i][j];

    // Add matrices
    for(int i = 0; i < 3; i++)
        for(int j = 0; j < 3; j++)
            C[i][j] = A[i][j] + B[i][j];

    // Display result
    cout << "Result Matrix:\n";
    for(int i = 0; i < 3; i++) {
        for(int j = 0; j < 3; j++)
            cout << C[i][j] << " ";
        cout << "\n";
    }
    return 0;
}

